  "inlineSchema": "// Aangan — Society Maintenance Tracker\n// Multi-tenant schema: every operational table carries societyId.\n// No query anywhere in the app should ever read/write across societies.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  ADMIN\n  RESIDENT\n}\n\nenum ComplaintStatus {\n  OPEN\n  IN_PROGRESS\n  RESOLVED\n}\n\nenum Priority {\n  LOW\n  MEDIUM\n  HIGH\n}\n\n// A society is the tenant boundary. Every other table (except User's auth\n// fields) is scoped to a societyId, and every backend query filters by it.\nmodel Society {\n  id                   String   @id @default(uuid())\n  name                 String\n  address              String?\n  joinCode             String   @unique // e.g. \"PLM-7K2X\" — admin shares this with residents\n  overdueThresholdDays Int      @default(7)\n  createdAt            DateTime @default(now())\n  updatedAt            DateTime @updatedAt\n\n  users      User[]\n  complaints Complaint[]\n  notices    Notice[]\n\n  @@map(\"societies\")\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  name         String\n  email        String   @unique\n  passwordHash String\n  role         Role\n  flatNumber   String? // residents only\n  createdAt    DateTime @default(now())\n\n  societyId String\n  society   Society @relation(fields: [societyId], references: [id], onDelete: Cascade)\n\n  complaintsRaised Complaint[]        @relation(\"RaisedBy\")\n  historyChanges   ComplaintHistory[] @relation(\"ChangedBy\")\n  noticesPosted    Notice[]           @relation(\"PostedBy\")\n\n  @@index([societyId])\n  @@map(\"users\")\n}\n\nmodel Complaint {\n  id          String          @id @default(uuid())\n  title       String\n  description String\n  category    String\n  status      ComplaintStatus @default(OPEN)\n  priority    Priority        @default(LOW)\n  photoUrl    String?\n  isOverdue   Boolean         @default(false)\n  createdAt   DateTime        @default(now())\n  updatedAt   DateTime        @updatedAt\n  resolvedAt  DateTime?\n\n  societyId String\n  society   Society @relation(fields: [societyId], references: [id], onDelete: Cascade)\n\n  residentId String\n  resident   User   @relation(\"RaisedBy\", fields: [residentId], references: [id])\n\n  history ComplaintHistory[]\n\n  @@index([societyId])\n  @@index([societyId, status])\n  @@index([societyId, category])\n  @@map(\"complaints\")\n}\n\n// Immutable audit trail — every status change is appended here, never edited.\nmodel ComplaintHistory {\n  id          String    @id @default(uuid())\n  complaintId String\n  complaint   Complaint @relation(fields: [complaintId], references: [id], onDelete: Cascade)\n\n  oldStatus ComplaintStatus?\n  newStatus ComplaintStatus\n  note      String?\n  changedAt DateTime         @default(now())\n\n  changedById String\n  changedBy   User   @relation(\"ChangedBy\", fields: [changedById], references: [id])\n\n  @@index([complaintId])\n  @@map(\"complaint_history\")\n}\n\nmodel Notice {\n  id          String   @id @default(uuid())\n  title       String\n  content     String\n  isImportant Boolean  @default(false)\n  createdAt   DateTime @default(now())\n\n  societyId String\n  society   Society @relation(fields: [societyId], references: [id], onDelete: Cascade)\n\n  postedById String\n  postedBy   User   @relation(\"PostedBy\", fields: [postedById], references: [id])\n\n  @@index([societyId])\n  @@index([societyId, isImportant])\n  @@map(\"notices\")\n}\n",
